@@ -26131,8 +26131,20 @@ impl Connection {
             return;
         };

-        if !retain_for_memory_autocommit && let Some(cached_leaf) = hint.cached_leaf.take() {
-            hint.cached_leaf = Some(cached_leaf.without_page_data());
+        if !retain_for_memory_autocommit
+            && let Some(cached_leaf) = hint.cached_leaf.as_mut()
+        {
+            // In-place page-data strip. The previous shape was
+            // `take() → without_page_data(self) → Some(..)` which
+            // forced two by-value moves of the ~100-byte
+            // `TableAppendHint` per row on the INSERT hotpath;
+            // `clear_page_data(&mut self)` drops the same field in
+            // place with zero struct copies. See the
+            // `TableAppendHint::clear_page_data` doc for the
+            // profile-attribution story (1-thread
+            // `store_prepared_direct_insert_append_hint` = 3.98 % self-
+            // time pre-fix).
+            cached_leaf.clear_page_data();
         }

         *self.prepared_direct_insert_append_hint.borrow_mut() = Some(hint);
